const today = new Date().toISOString().slice(0, 10);
const aiOutput = $input.first().json;
const raw = aiOutput?.message?.content?.[0]?.text
         || aiOutput?.content?.[0]?.text
         || aiOutput?.text || '';

const jsonMatch = raw.match(/{[sS]*}/);
if (!jsonMatch) throw new Error('No JSON found in AI response');

const parsed = JSON.parse(jsonMatch[0]);

const emailData = $('Email Trigger (IMAP)').first().json;
const from = emailData.from;
let fromText = '';
if (typeof from === 'string') { fromText = from; }
else { fromText = from?.text || from?.value?.[0]?.name || from?.value?.[0]?.address || ''; }

const returnPath = emailData.metadata?.['return-path'] || '';
const senderEmail = from?.value?.[0]?.address
                 || fromText.match(/[w.-]+@[w.-]+.w+/)?.[0]
                 || returnPath.replace(/[<>]/g, '').trim()
                 || '';

const badTitle = !parsed.title
    || parsed.title.toLowerCase().includes('no email')
    || parsed.title.toLowerCase().includes('unable to extract')
    || parsed.title.toLowerCase().includes('not provided')
    || parsed.title.trim().length < 3;

if (badTitle) {
    return [{ json: { valid: false, createdBy: senderEmail } }];
}

if (!parsed.dueDate || parsed.dueDate < today) {
    parsed.dueDate = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
}

const nameMatch = fromText.match(/^([^<]+)</);
if (nameMatch) { parsed.createdByName = nameMatch[1].trim(); }
else if (fromText.includes('@')) { parsed.createdByName = fromText.split('@')[0]; }
else { parsed.createdByName = fromText || ''; }

parsed.createdBy = senderEmail;
parsed.description = (parsed.description || '') + ' — Dieses Ticket wurde KI-generiert.';

const subtasksRaw = Array.isArray(parsed.subtasks) ? parsed.subtasks : [];
const subtasksForFirestore = subtasksRaw.map(t => ({
    mapValue: {
        fields: {
            title: { stringValue: typeof t === 'string' ? t : (t.title || '') },
            completed: { booleanValue: false }
        }
    }
}));

const firestoreBody = JSON.stringify({
    fields: {
        title: { stringValue: parsed.title || '' },
        description: { stringValue: (parsed.description || '').replace(/[
]/g, ' ') },
        dueDate: { stringValue: parsed.dueDate || '' },
        category: { stringValue: parsed.category || '' },
        prio: { stringValue: parsed.prio || '' },
        status: { stringValue: 'triage' },
        subtasks: { arrayValue: { values: subtasksForFirestore } },
        assignedContacts: { arrayValue: { values: [] } },
        createdBy: { stringValue: parsed.createdBy || '' },
        createdByName: { stringValue: parsed.createdByName || '' },
        creatorType: { stringValue: 'external' },
        aiGenerated: { booleanValue: true }
    }
});

return [{ json: { ...parsed, valid: true, firestoreBody } }];

const today = new Date().toISOString().slice(0, 10);
const doc = $input.first().json;
const currentDate = doc.fields?.date?.stringValue || '';
const currentCount = parseInt(doc.fields?.count?.integerValue || 0);
const newCount = currentDate === today ? currentCount + 1 : 1;
return [{ json: { count: newCount, date: today } }];
